SELECT u.id, u.username, u.nickname, u.user_profile AS userProfile, u.user_state_id AS userStateId, u.user_type_id AS userTypeId, MAX(m.create_time) AS lastMessageTime FROM user u INNER JOIN private_msg_content m ON (u.id = m.from_id OR u.id = m.to_id) INNER JOIN private_chat_conversation c ON m.conversation_id = c.id WHERE -- 1. 基础过滤：排除自己，限制时间 u.id != #{currentUserId} AND m.create_time >= DATE_SUB(NOW(), INTERVAL 3 DAY)
-- 2. 限制为当前服务域 AND c.service_domain_id = #{serviceDomainId}
-- 3. 核心修正：可见性规则 (使用括号包裹 OR 条件) AND ( -- 情况 A: 我参与的会话 (无论是进行中还是已结束都能看) (c.user_id_1 = #{currentUserId} OR c.user_id_2 = #{currentUserId}) OR -- 情况 B: 别人的会话 (必须是已结束的) (c.is_active = 0) ) AND u.user_type_id = 0 GROUP BY u.id ORDER BY lastMessageTime DESC

